package org.apache.commons.collections4;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.collections4.steps",
    plugin = {"pretty", "html:target/cucumber-reports.html"}
)
public class CucumberTest {
}

package org.apache.commons.collections4.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.When;
import org.apache.commons.collections4.IteratorUtils;
import org.junit.Assert;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.Iterator;
import java.util.List;
import java.util.stream.Collectors;

public class StepDefs {

    private List<Integer> oddList;
    private List<Integer> evenList;
    private Iterator<Integer> resultIterator;
    private Exception caughtException;
    private List<Integer> resultList;

    @Given("a list of odd integers: {int}, {int}, {int}, {int}, {int}, {int}")
    public void a_list_of_odd_integers(int i1, int i2, int i3, int i4, int i5, int i6) {
        oddList = Arrays.asList(i1, i2, i3, i4, i5, i6);
    }

    @Given("a list of even integers: {int}, {int}, {int}, {int}, {int}, {int}")
    public void a_list_of_even_integers(int i1, int i2, int i3, int i4, int i5, int i6) {
        evenList = Arrays.asList(i1, i2, i3, i4, i5, i6);
    }

    @When("IteratorUtils.collatedIterator is called with a null comparator and iterators for these lists")
    public void iterator_utils_collated_iterator_is_called_with_a_null_comparator_and_iterators_for_these_lists() {
        try {
            resultIterator = IteratorUtils.collatedIterator(null, oddList.iterator(), evenList.iterator());
        } catch (Exception e) {
            caughtException = e;
        }
    }

    @Then("the returned iterator should produce the sequence: {int}, {int}, {int}, {int}, {int}, {int}, {int}, {int}, {int}, {int}, {int}, {int}")
    public void the_returned_iterator_should_produce_the_sequence(int i1, int i2, int i3, int i4, int i5, int i6, int i7, int i8, int i9, int i10, int i11, int i12) {
        List<Integer> expected = Arrays.asList(i1, i2, i3, i4, i5, i6, i7, i8, i9, i10, i11, i12);

        if (caughtException != null) {
             Assert.fail("Exception thrown during creation: " + caughtException.getMessage());
        }

        resultList = new ArrayList<>();
        try {
            while (resultIterator.hasNext()) {
                resultList.add(resultIterator.next());
            }
        } catch (Exception e) {
             caughtException = e;
        }

        Assert.assertEquals("Sequence mismatch", expected, resultList);
    }

    @Then("the iterator iteration should complete without throwing a NullPointerException")
    public void the_iterator_iteration_should_complete_without_throwing_a_null_pointer_exception() {
        if (caughtException instanceof NullPointerException) {
             Assert.fail("NullPointerException was thrown: " + caughtException.getStackTrace()[0]);
        }
        if (caughtException != null) {
            Assert.fail("An exception was thrown: " + caughtException.getClass().getName());
        }
    }
}
